import { useEffect, useState } from "react";

export default function ClubOverview({ clubId }) {
    const [club, setClub] = useState(null);

    useEffect(() => {
        fetch(`/api/clubs/${clubId}`)
            .then(r => r.json())
            .then(setClub);
    }, [clubId]);

    if (!club) return <div>Loading…</div>;

    return (
        <div className="card">
            <h3>Description</h3>
            <p>{club.description}</p>
        </div>
    );
}
